const UP_POST= 'UP_POST';
const ADD_POST = 'ADD_POST';

let initialState ={
        post:'text',
};

function postReducer(state = initialState , action) {

switch(action.type){
  case UP_POST:{
  let stateCopy = {...state} ;
stateCopy.upPost = action.upPost;
return stateCopy;
} 
case ADD_POST:
   let addPost = {
      post: state.post,
    };
    let stateCopy = {...state} ;
stateCopy.post = [...state.post] ;
    stateCopy.post.push(addPost);
    stateCopy.post = '777';
  return stateCopy;
default:
 return state;
 };
};


export const creatorUpPost = (text) => {
  return {
    type:'UP_POST',
    upPost:text,
  }
};

